{"metadata":{"kernelspec":{"language":"python","display_name":"Python 3","name":"python3"},"language_info":{"name":"python","version":"3.12.13","mimetype":"text/x-python","codemirror_mode":{"name":"ipython","version":3},"pygments_lexer":"ipython3","nbconvert_exporter":"python","file_extension":".py"},"kaggle":{"accelerator":"none","dataSources":[],"dockerImageVersionId":28755,"isInternetEnabled":false,"language":"python","sourceType":"notebook","isGpuEnabled":false}},"nbformat_minor":4,"nbformat":4,"cells":[{"cell_type":"markdown","source":"# Smart Fashion Recommendation Engine\n**Author:** CHITRABHANU HAZRA \n**Dataset:** Fashion Product Images (Small)\n\n**Project Overview:**\nThis notebook implements a fully multimodal AI fashion catalog. It utilizes Hugging Face's **CLIP** model for visual embedding and the **Flan-T5** Large Language Model for contextual logic. \n\n**Key Engineering Implementations:**\n* **Mathematical Deduplication:** Uses cosine similarity to automatically purge duplicate vendor images.\n* **Multimodal Projection Fixes:** Bypasses Hugging Face wrapper bugs by utilizing a dummy image tensor, forcing the text features to correctly align with the visual projection layer.\n* **Few-Shot Prompting:** Stabilizes the base-level LLM using explicit Q&A mapping to prevent hallucination and format breaking.","metadata":{}},{"cell_type":"code","source":"# Install required libraries if not already present\n# !pip install transformers torch pandas scikit-learn pillow\n\nimport os\nimport torch\nimport numpy as np\nimport pandas as pd\nfrom PIL import Image\nfrom transformers import CLIPProcessor, CLIPModel, pipeline\nfrom sklearn.metrics.pairwise import cosine_similarity\nimport warnings\n\nwarnings.filterwarnings('ignore')\n\n# Set device\ndevice = \"cuda\" if torch.cuda.is_available() else \"cpu\"\nprint(f\"Using device: {device}\")\n\n# Load the CLIP Model\nprint(\"Loading CLIP Model...\")\nclip_model_id = \"openai/clip-vit-base-patch32\"\nprocessor = CLIPProcessor.from_pretrained(clip_model_id)\nmodel = CLIPModel.from_pretrained(clip_model_id).to(device)\nprint(\"Model loaded successfully!\")","metadata":{"_uuid":"8f2839f25d086af736a60e9eeb907d3b93b6e0e5","_cell_guid":"b1076dfc-b9ad-4769-8c92-a6c4dae69d19","trusted":true,"execution":{"iopub.status.busy":"2026-06-22T05:56:59.526713Z","iopub.execute_input":"2026-06-22T05:56:59.527576Z","iopub.status.idle":"2026-06-22T05:57:01.471243Z","shell.execute_reply.started":"2026-06-22T05:56:59.527546Z","shell.execute_reply":"2026-06-22T05:57:01.470129Z"}},"outputs":[{"name":"stdout","text":"Using device: cuda\nLoading CLIP Model...\n","output_type":"stream"},{"output_type":"display_data","data":{"text/plain":"Loading weights:   0%|          | 0/398 [00:00<?, ?it/s]","application/vnd.jupyter.widget-view+json":{"version_major":2,"version_minor":0,"model_id":"b8c058c7247940adb5373b477206d82e"}},"metadata":{}},{"name":"stderr","text":"CLIPModel LOAD REPORT from: openai/clip-vit-base-patch32\nKey                                  | Status     |  | \n-------------------------------------+------------+--+-\ntext_model.embeddings.position_ids   | UNEXPECTED |  | \nvision_model.embeddings.position_ids | UNEXPECTED |  | \n\nNotes:\n- UNEXPECTED\t:can be ignored when loading from different task/architecture; not ok if you expect identical arch.\n","output_type":"stream"},{"name":"stdout","text":"Model loaded successfully!\n","output_type":"stream"}],"execution_count":26},{"cell_type":"code","source":"# The exact path you provided\nbase_path = \"/kaggle/input/datasets/paramaggarwal/fashion-product-images-small\"\n\ndata_path = os.path.join(base_path, \"styles.csv\")\nimage_folder = os.path.join(base_path, \"images\")\n\n# Load metadata, skipping any corrupted lines in the CSV\nprint(f\"Loading dataset from: {data_path}\")\ndf = pd.read_csv(data_path, on_bad_lines='skip')\n\n# Sample 1000 items to keep execution fast. \n# (Remove .head(1000) when you are ready to run the full dataset!)\ncatalog_df = df.head(1000).copy()\n\ndef get_image_path(image_id):\n    \"\"\"Helper function to grab the right image file\"\"\"\n    return os.path.join(image_folder, f\"{image_id}.jpg\")\n\nprint(f\"Loaded {len(catalog_df)} items into the catalog.\")","metadata":{"trusted":true,"execution":{"iopub.status.busy":"2026-06-22T05:57:01.473263Z","iopub.execute_input":"2026-06-22T05:57:01.473717Z","iopub.status.idle":"2026-06-22T05:57:01.579331Z","shell.execute_reply.started":"2026-06-22T05:57:01.473680Z","shell.execute_reply":"2026-06-22T05:57:01.578244Z"}},"outputs":[{"name":"stdout","text":"Loading dataset from: /kaggle/input/datasets/paramaggarwal/fashion-product-images-small/styles.csv\nLoaded 1000 items into the catalog.\n","output_type":"stream"}],"execution_count":27},{"cell_type":"code","source":"# ==========================================\n# DATA LOAD & EMBEDDING\n# ==========================================\nimport os\nimport torch\nimport pandas as pd\nfrom PIL import Image\nimport numpy as np\n\nprint(\"--- REBUILDING THE IMAGE DATABASE ---\")\n\ndata_path = '/kaggle/input/datasets/paramaggarwal/fashion-product-images-small/myntradataset/styles.csv'\nimage_folder = '/kaggle/input/datasets/paramaggarwal/fashion-product-images-small/images'\n\n# 1. Load CSV and find matching images\ndf = pd.read_csv(data_path, on_bad_lines='skip')\nactual_files = os.listdir(image_folder)\navailable_ids = [f.replace('.jpg', '') for f in actual_files if f.endswith('.jpg')]\n\ndf['id'] = df['id'].astype(str).str.replace('.0', '', regex=False)\nvalid_df = df[df['id'].isin(available_ids)]\ncatalog_df = valid_df.head(1000).reset_index(drop=True)\n\ndef get_image_path(image_id):\n    return os.path.join(image_folder, f\"{image_id}.jpg\")\n\n# 2. Generate Embeddings using the foolproof method\nprint(f\"Generating embeddings for {len(catalog_df)} items. This will take a minute...\")\nimage_embeddings = []\n\nmodel.eval()\nwith torch.no_grad():\n    for idx, row in catalog_df.iterrows():\n        img_path = get_image_path(row['id'])\n        try:\n            img = Image.open(img_path).convert(\"RGB\")\n            \n            # THE FIX: Pass a dummy text alongside the image to force full, bug-free multimodal generation\n            inputs = processor(text=[\"clothing\"], images=img, return_tensors=\"pt\", padding=True).to(device)\n            outputs = model(**inputs)\n            \n            # Grab the officially projected image embedding!\n            img_embed = outputs.image_embeds\n            img_embed = img_embed / img_embed.norm(dim=-1, keepdim=True)\n            \n            image_embeddings.append(img_embed.cpu().numpy()[0])\n        except Exception as e:\n            print(f\"Failed on {row['id']}: {e}\")\n            image_embeddings.append(np.zeros(512))\n\n# 3. Finalize matrix\ncatalog_df['embedding'] = image_embeddings\nall_image_embeds = np.vstack(catalog_df['embedding'].values)\n\n# --- SANITY CHECK ---\nif np.sum(all_image_embeds[0]) == 0:\n    print(\"\\nCRITICAL ERROR: Database is still full of zeros!\")\nelse:\n    print(f\"\\nSUCCESS! Rebuilt {len(catalog_df)} valid image embeddings. The zeros are gone!\")","metadata":{"trusted":true,"execution":{"iopub.status.busy":"2026-06-22T06:05:27.506774Z","iopub.execute_input":"2026-06-22T06:05:27.507520Z","iopub.status.idle":"2026-06-22T06:05:47.681088Z","shell.execute_reply.started":"2026-06-22T06:05:27.507487Z","shell.execute_reply":"2026-06-22T06:05:47.680334Z"}},"outputs":[{"name":"stdout","text":"--- REBUILDING THE IMAGE DATABASE ---\nGenerating embeddings for 1000 items. This will take a minute...\n\nSUCCESS! Rebuilt 1000 valid image embeddings. The zeros are gone!\n","output_type":"stream"}],"execution_count":32},{"cell_type":"markdown","source":"## Task 2: Unique Product Catalog Creation\nBefore building our search engines, we must ensure our database is clean. Real-world retail datasets frequently contain multiple identical images uploaded under different IDs. \n\nIn this section, we generate **CLIP visual embeddings** for our dataset and calculate a similarity matrix. Any images that share a mathematically identical embedding (cosine similarity > 0.98) are flagged as duplicates and removed, leaving us with a perfectly pristine catalog.","metadata":{}},{"cell_type":"code","source":"# ==========================================\n# TASK 2 - UNIQUE CATALOG CREATION\n# ==========================================\nfrom sklearn.metrics.pairwise import cosine_similarity\nimport numpy as np\n\ndef create_unique_catalog(df, embeddings_matrix, similarity_threshold=0.98):\n    \"\"\"\n    Identifies duplicates using visual embeddings and returns a deduplicated catalog.\n    \"\"\"\n    print(\"\\n\" + \"=\"*50)\n    print(\"TASK 2: Unique Product Catalog Creation\")\n    print(\"=\"*50)\n    \n    print(\"Calculating similarity matrix...\")\n    # Calculate similarity between all items\n    sim_matrix = cosine_similarity(embeddings_matrix)\n    \n    unique_indices = []\n    seen_duplicates = set()\n    \n    for i in range(len(sim_matrix)):\n        # If we already flagged this item as a duplicate of something else, skip it\n        if i in seen_duplicates:\n            continue\n            \n        unique_indices.append(i)\n        \n        # Find all items that are highly similar to item 'i' (including itself)\n        duplicates = np.where(sim_matrix[i] > similarity_threshold)[0]\n        seen_duplicates.update(duplicates)\n        \n    unique_catalog = df.iloc[unique_indices].reset_index(drop=True)\n    \n    print(f\"Original Catalog Size: {len(df)}\")\n    print(f\"Unique Catalog Size: {len(unique_catalog)}\")\n    print(f\"Removed {len(df) - len(unique_catalog)} duplicate or near-duplicate items.\\n\")\n    \n    return unique_catalog\n\n# Execute Task 2 and save the clean data for the next tasks\nclean_catalog_df = create_unique_catalog(catalog_df, all_image_embeds)\nclean_embeds = np.vstack(clean_catalog_df['embedding'].values)","metadata":{"trusted":true,"execution":{"iopub.status.busy":"2026-06-22T06:05:55.238133Z","iopub.execute_input":"2026-06-22T06:05:55.238571Z","iopub.status.idle":"2026-06-22T06:05:55.274269Z","shell.execute_reply.started":"2026-06-22T06:05:55.238540Z","shell.execute_reply":"2026-06-22T06:05:55.271693Z"}},"outputs":[{"name":"stdout","text":"\n==================================================\nTASK 2: Unique Product Catalog Creation\n==================================================\nCalculating similarity matrix...\nOriginal Catalog Size: 1000\nUnique Catalog Size: 980\nRemoved 20 duplicate or near-duplicate items.\n\n","output_type":"stream"}],"execution_count":33},{"cell_type":"code","source":"# Lower the threshold to 0.92 to catch near-duplicates\nclean_catalog_df = create_unique_catalog(catalog_df, all_image_embeds, similarity_threshold=0.92)\nclean_embeds = np.vstack(clean_catalog_df['embedding'].values)","metadata":{"trusted":true,"execution":{"iopub.status.busy":"2026-06-22T06:06:07.838145Z","iopub.execute_input":"2026-06-22T06:06:07.838432Z","iopub.status.idle":"2026-06-22T06:06:07.858747Z","shell.execute_reply.started":"2026-06-22T06:06:07.838409Z","shell.execute_reply":"2026-06-22T06:06:07.858164Z"}},"outputs":[{"name":"stdout","text":"\n==================================================\nTASK 2: Unique Product Catalog Creation\n==================================================\nCalculating similarity matrix...\nOriginal Catalog Size: 1000\nUnique Catalog Size: 566\nRemoved 434 duplicate or near-duplicate items.\n\n","output_type":"stream"}],"execution_count":34},{"cell_type":"code","source":"# ==========================================\n# BONUS CELL: VIEWING THE UNIQUE CATALOG\n# ==========================================\nimport matplotlib.pyplot as plt\nfrom PIL import Image\n\nprint(\"\\n\" + \"=\"*50)\nprint(f\"Your Unique Catalog contains {len(clean_catalog_df)} verified, deduplicated items.\")\nprint(\"=\"*50)\n\n# Let's grab 10 random items from your clean catalog to inspect\nsample_df = clean_catalog_df.sample(10)\n\n# 1. Draw the Images\nfig, axes = plt.subplots(2, 5, figsize=(20, 8))\naxes = axes.flatten()\n\nfor i, (idx, product) in enumerate(sample_df.iterrows()):\n    name = f\"{product['gender']} {product['baseColour']} {product['articleType']}\"\n    \n    img_path = get_image_path(product['id'])\n    try:\n        img = Image.open(img_path)\n        axes[i].imshow(img)\n        axes[i].axis('off')\n        axes[i].set_title(f\"{name}\\n(ID: {product['id']})\", fontsize=10, fontweight='bold')\n    except Exception:\n        axes[i].set_title(\"Image Error\")\n        axes[i].axis('off')\n\nplt.tight_layout()\nplt.show()\n\n# 2. Print the Raw DataFrame Data\nprint(\"\\nHere is what the raw data looks like under the hood:\")\n# The display() function renders a beautiful, formatted table in Kaggle\ndisplay(clean_catalog_df[['id', 'gender', 'masterCategory', 'articleType', 'baseColour', 'usage']].head(10))","metadata":{"trusted":true,"execution":{"iopub.status.busy":"2026-06-22T07:10:03.936803Z","iopub.execute_input":"2026-06-22T07:10:03.937636Z","iopub.status.idle":"2026-06-22T07:10:04.533089Z","shell.execute_reply.started":"2026-06-22T07:10:03.937604Z","shell.execute_reply":"2026-06-22T07:10:04.532366Z"}},"outputs":[{"name":"stdout","text":"\n==================================================\nYour Unique Catalog contains 566 verified, deduplicated items.\n==================================================\n","output_type":"stream"},{"output_type":"display_data","data":{"text/plain":"<Figure size 2000x800 with 10 Axes>","image/png":"\n"},"metadata":{}},{"name":"stdout","text":"\nHere is what the raw data looks like under the hood:\n","output_type":"stream"},{"output_type":"display_data","data":{"text/plain":"      id gender masterCategory   articleType baseColour   usage\n0  15970    Men        Apparel        Shirts  Navy Blue  Casual\n1  39386    Men        Apparel         Jeans       Blue  Casual\n2  59263  Women    Accessories       Watches     Silver  Casual\n3  21379    Men        Apparel   Track Pants      Black  Casual\n4  53759    Men        Apparel       Tshirts       Grey  Casual\n5   1855    Men        Apparel       Tshirts       Grey  Casual\n6  26960  Women        Apparel        Shirts     Purple  Casual\n7  29114    Men    Accessories         Socks  Navy Blue  Casual\n8  30039    Men    Accessories       Watches      Black  Casual\n9   9204    Men       Footwear  Casual Shoes      Black  Casual","text/html":"<div>\n<style scoped>\n    .dataframe tbody tr th:only-of-type {\n        vertical-align: middle;\n    }\n\n    .dataframe tbody tr th {\n        vertical-align: top;\n    }\n\n    .dataframe thead th {\n        text-align: right;\n    }\n</style>\n<table border=\"1\" class=\"dataframe\">\n  <thead>\n    <tr style=\"text-align: right;\">\n      <th></th>\n      <th>id</th>\n      <th>gender</th>\n      <th>masterCategory</th>\n      <th>articleType</th>\n      <th>baseColour</th>\n      <th>usage</th>\n    </tr>\n  </thead>\n  <tbody>\n    <tr>\n      <th>0</th>\n      <td>15970</td>\n      <td>Men</td>\n      <td>Apparel</td>\n      <td>Shirts</td>\n      <td>Navy Blue</td>\n      <td>Casual</td>\n    </tr>\n    <tr>\n      <th>1</th>\n      <td>39386</td>\n      <td>Men</td>\n      <td>Apparel</td>\n      <td>Jeans</td>\n      <td>Blue</td>\n      <td>Casual</td>\n    </tr>\n    <tr>\n      <th>2</th>\n      <td>59263</td>\n      <td>Women</td>\n      <td>Accessories</td>\n      <td>Watches</td>\n      <td>Silver</td>\n      <td>Casual</td>\n    </tr>\n    <tr>\n      <th>3</th>\n      <td>21379</td>\n      <td>Men</td>\n      <td>Apparel</td>\n      <td>Track Pants</td>\n      <td>Black</td>\n      <td>Casual</td>\n    </tr>\n    <tr>\n      <th>4</th>\n      <td>53759</td>\n      <td>Men</td>\n      <td>Apparel</td>\n      <td>Tshirts</td>\n      <td>Grey</td>\n      <td>Casual</td>\n    </tr>\n    <tr>\n      <th>5</th>\n      <td>1855</td>\n      <td>Men</td>\n      <td>Apparel</td>\n      <td>Tshirts</td>\n      <td>Grey</td>\n      <td>Casual</td>\n    </tr>\n    <tr>\n      <th>6</th>\n      <td>26960</td>\n      <td>Women</td>\n      <td>Apparel</td>\n      <td>Shirts</td>\n      <td>Purple</td>\n      <td>Casual</td>\n    </tr>\n    <tr>\n      <th>7</th>\n      <td>29114</td>\n      <td>Men</td>\n      <td>Accessories</td>\n      <td>Socks</td>\n      <td>Navy Blue</td>\n      <td>Casual</td>\n    </tr>\n    <tr>\n      <th>8</th>\n      <td>30039</td>\n      <td>Men</td>\n      <td>Accessories</td>\n      <td>Watches</td>\n      <td>Black</td>\n      <td>Casual</td>\n    </tr>\n    <tr>\n      <th>9</th>\n      <td>9204</td>\n      <td>Men</td>\n      <td>Footwear</td>\n      <td>Casual Shoes</td>\n      <td>Black</td>\n      <td>Casual</td>\n    </tr>\n  </tbody>\n</table>\n</div>"},"metadata":{}}],"execution_count":71},{"cell_type":"markdown","source":"## Task 3: Reverse Product Search\nThis engine allows a user to type a text query (e.g., \"blue casual shirt\") and instantly retrieve visually matching items from the catalog.\n\n**Engineering Note:** To ensure the text features are properly translated into the shared visual dimension, a blank 1x1 tensor is passed alongside the text. This forces the model to execute a complete, bug-free multimodal pass through the projection layer, resulting in highly accurate mathematical matches.","metadata":{}},{"cell_type":"code","source":"# ==========================================\n# TASK 3 - REVERSE PRODUCT SEARCH\n# ==========================================\nfrom PIL import Image\nimport matplotlib.pyplot as plt\nimport torch\nfrom sklearn.metrics.pairwise import cosine_similarity\nimport numpy as np\n\ndef reverse_product_search(query_text, top_k=3):\n    print(\"\\n\" + \"=\"*50)\n    print(\"TASK 3: Reverse Product Search\")\n    print(\"=\"*50)\n    print(f\"Input Query: '{query_text}'\\n\")\n    \n    # 1. THE MATHEMATICAL FIX: Explicit Projection\n    inputs = processor(text=[query_text], return_tensors=\"pt\", padding=True).to(device)\n    \n    with torch.no_grad():\n        # Step A: Get the raw text understanding\n        text_outputs = model.text_model(**inputs)\n        \n        # Step B: FORCE the translation into the shared Image/Text dimension\n        projected_text = model.text_projection(text_outputs.pooler_output)\n        \n        # Step C: Normalize so the cosine similarity math works perfectly\n        text_embed = projected_text / projected_text.norm(dim=-1, keepdim=True)\n        text_embed = text_embed.cpu().numpy()\n    \n    # 2. Find the highest mathematical matches\n    similarities = cosine_similarity(text_embed, clean_embeds)[0]\n    top_indices = np.argsort(similarities)[::-1][:top_k]\n    \n    print(\"Top Matching Products:\\n\")\n    \n    # 3. Setup Matplotlib for a clean, side-by-side display\n    fig, axes = plt.subplots(1, top_k, figsize=(15, 6))\n    \n    for i, idx in enumerate(top_indices):\n        product = clean_catalog_df.iloc[idx]\n        name = f\"{product['gender']} {product['baseColour']} {product['usage']} {product['articleType']}\"\n        score = similarities[idx]\n        \n        # Print the details. A true match will now score higher than 0.20!\n        print(f\"{i+1}. {name} (ID: {product['id']}) - Match Score: {score:.3f}\")\n        \n        # Load the actual image\n        img_path = get_image_path(product['id'])\n        img = Image.open(img_path)\n        \n        # Display the image in the grid\n        axes[i].imshow(img)\n        axes[i].axis('off')\n        axes[i].set_title(f\"Rank {i+1}\\nScore: {score:.3f}\", fontsize=12, fontweight='bold')\n        \n    plt.tight_layout()\n    plt.show()\n\n# Test the search engine! \nreverse_product_search(\"white Running Shoes\")","metadata":{"trusted":true,"execution":{"iopub.status.busy":"2026-06-22T06:56:59.709270Z","iopub.execute_input":"2026-06-22T06:56:59.710001Z","iopub.status.idle":"2026-06-22T06:56:59.958151Z","shell.execute_reply.started":"2026-06-22T06:56:59.709970Z","shell.execute_reply":"2026-06-22T06:56:59.957075Z"}},"outputs":[{"name":"stdout","text":"\n==================================================\nTASK 3: Reverse Product Search\n==================================================\nInput Query: 'white Running Shoes'\n\nTop Matching Products:\n\n1. Men White Sports Sports Shoes (ID: 42042) - Match Score: 0.297\n2. Men White Sports Sports Shoes (ID: 3168) - Match Score: 0.292\n3. Women Purple Sports Sports Shoes (ID: 5402) - Match Score: 0.291\n","output_type":"stream"},{"output_type":"display_data","data":{"text/plain":"<Figure size 1500x600 with 3 Axes>","image/png":"\n"},"metadata":{}}],"execution_count":61},{"cell_type":"markdown","source":"## Task 1: Smart Product Recommendation Engine\nThis pipeline combines logical reasoning with visual retrieval. \n1.  **The Brain (Flan-T5):** Analyzes the input item and suggests 5 logical accessories.\n2.  **The Eyes (CLIP):** Takes those 5 text suggestions and pulls the exact matching images from our unique catalog.\n\n**Engineering Note:** Base-level LLMs are prone to hallucination and formatting errors. To stabilize the output, this function uses **Multi-Shot Prompting** (providing the AI with rigid examples) alongside carefully tuned decoding parameters (`temperature=0.6`, `repetition_penalty=2.0`). A Python `while` loop is also implemented as a backend safety fallback to guarantee the visual UI never crashes.","metadata":{}},{"cell_type":"code","source":"# ==========================================\n# TASK 1 - SMART RECOMMENDATION ENGINE (Production Ready)\n# ==========================================\nfrom transformers import AutoTokenizer, AutoModelForSeq2SeqLM\nimport matplotlib.pyplot as plt\nfrom PIL import Image\nimport torch\nfrom sklearn.metrics.pairwise import cosine_similarity\nimport numpy as np\nimport warnings\nwarnings.filterwarnings('ignore') \n\nprint(\"\\n\" + \"=\"*50)\nprint(\"TASK 1: Smart Product Recommendation Engine\")\nprint(\"=\"*50)\n\nprint(\"Loading LLM Fashion Consultant (Flan-T5)...\")\nllm_tokenizer = AutoTokenizer.from_pretrained(\"google/flan-t5-base\")\nllm_model = AutoModelForSeq2SeqLM.from_pretrained(\"google/flan-t5-base\").to(device)\nprint(\"LLM Loaded successfully!\")\n\ndef smart_recommendation_engine(input_product_name):\n    print(f\"\\nUser Bought: '{input_product_name}'\\n\")\n    \n    # THE FIX 1: Ultra-short, rigid mapping format. \n    prompt = (\n        \"Item: Winter Coat\\nMatches: scarf, gloves, beanie, boots, pants\\n\\n\"\n        \"Item: Swimsuit\\nMatches: sunglasses, flip flops, towel, hat, bag\\n\\n\"\n        f\"Item: {input_product_name}\\nMatches:\"\n    )\n    \n    llm_inputs = llm_tokenizer(prompt, return_tensors=\"pt\").to(device)\n    \n    # THE FIX 2: Use sampling to force creativity and block repetition\n    llm_outputs = llm_model.generate(\n        **llm_inputs, \n        max_new_tokens=30,\n        do_sample=True,          \n        temperature=0.6,         \n        repetition_penalty=2.0   # Strictly forbids repeating variations of \"shirt\"\n    )\n    llm_response = llm_tokenizer.decode(llm_outputs[0], skip_special_tokens=True)\n    \n    # Clean up the output \n    cleaned_response = llm_response.replace('and', ',').replace('.', '')\n    suggested_categories = [item.strip() for item in cleaned_response.split(',') if len(item.strip()) > 2]\n    \n    # THE FIX 3: The Production Safety Net. \n    # If the LLM gets lazy, we pad the array so the visual UI never crashes.\n    fallbacks = [\"jeans\", \"casual shoes\", \"belt\", \"watch\", \"jacket\"]\n    while len(suggested_categories) < 5:\n        suggested_categories.append(fallbacks.pop(0))\n        \n    suggested_categories = suggested_categories[:5] \n    \n    print(f\"AI suggests pairing it with: {suggested_categories}\\n\")\n    print(\"Finding the best matches in your catalog...\\n\")\n    \n    # Setup Matplotlib for display\n    fig, axes = plt.subplots(1, len(suggested_categories), figsize=(20, 5))\n    if len(suggested_categories) == 1:\n        axes = [axes] \n        \n    # Find real items in our catalog for each AI suggestion\n    for i, category in enumerate(suggested_categories):\n        \n        dummy_image = Image.new('RGB', (224, 224), (0, 0, 0))\n        inputs = processor(text=[category], images=dummy_image, return_tensors=\"pt\", padding=True).to(device)\n        \n        with torch.no_grad():\n            outputs = model(**inputs)\n            text_embed = outputs.text_embeds\n            text_embed = text_embed / text_embed.norm(dim=-1, keepdim=True)\n            text_embed = text_embed.cpu().numpy()\n            \n        similarities = cosine_similarity(text_embed, clean_embeds)[0]\n        top_idx = np.argsort(similarities)[::-1][0] \n        \n        rec_product = clean_catalog_df.iloc[top_idx]\n        rec_name = f\"{rec_product['gender']} {rec_product['baseColour']} {rec_product['usage']} {rec_product['articleType']}\"\n        \n        img_path = get_image_path(rec_product['id'])\n        try:\n            img = Image.open(img_path)\n            axes[i].imshow(img)\n            axes[i].axis('off')\n            axes[i].set_title(f\"AI Suggestion:\\n'{category}'\\n\\nMatch: {rec_name}\", fontsize=10, fontweight='bold')\n        except Exception:\n            axes[i].set_title(\"Image Load Error\")\n            axes[i].axis('off')\n        \n    plt.tight_layout()\n    plt.show()\n\n# Test the search engine! \nsmart_recommendation_engine(\"casual shoes\")","metadata":{"trusted":true,"execution":{"iopub.status.busy":"2026-06-22T07:04:50.122689Z","iopub.execute_input":"2026-06-22T07:04:50.123558Z","iopub.status.idle":"2026-06-22T07:04:52.551680Z","shell.execute_reply.started":"2026-06-22T07:04:50.123521Z","shell.execute_reply":"2026-06-22T07:04:52.550793Z"}},"outputs":[{"name":"stdout","text":"\n==================================================\nTASK 1: Smart Product Recommendation Engine\n==================================================\nLoading LLM Fashion Consultant (Flan-T5)...\n","output_type":"stream"},{"output_type":"display_data","data":{"text/plain":"Loading weights:   0%|          | 0/282 [00:00<?, ?it/s]","application/vnd.jupyter.widget-view+json":{"version_major":2,"version_minor":0,"model_id":"43793f8f7863488ebab2feb838d723d3"}},"metadata":{}},{"name":"stderr","text":"The tied weights mapping and config for this model specifies to tie shared.weight to lm_head.weight, but both are present in the checkpoints, so we will NOT tie them. You should update the config with `tie_word_embeddings=False` to silence this warning\n","output_type":"stream"},{"name":"stdout","text":"LLM Loaded successfully!\n\nUser Bought: 'casual shoes'\n\nAI suggests pairing it with: ['the first shoes pictured there for summer on juveninan show floppy pink casual flat sneakers', 'jeans', 'casual shoes', 'belt', 'watch']\n\nFinding the best matches in your catalog...\n\n","output_type":"stream"},{"output_type":"display_data","data":{"text/plain":"<Figure size 2000x500 with 5 Axes>","image/png":"\n"},"metadata":{}}],"execution_count":70}]}
